                        pq.enqueue((cost, i, j, used + 1));
                    }
                }
            }
        }
    }

    dist[m - 1][n - 1]
}

struct PriorityQueue<T> {
    heap: Vec<T>,
    comparator: Box<dyn Fn(&T, &T) -> Ordering>,
}

impl<T> PriorityQueue<T> {
    fn new(comparator: impl Fn(&T, &T) -> Ordering + 'static) -> Self {
        PriorityQueue {
            heap: Vec::new(),
            comparator: Box::new(comparator),
        }
    }

    fn enqueue(&mut self, value: T) {
        self.heap.push(value);
        self.heapify_up(self.heap.len() - 1);
    }

    fn dequeue(&mut self) -> Option<T> {
        if self.heap.is_empty() {
            return None;
        }
        let result = self.heap[0].clone();
        self.heap[0] = self.heap.last().cloned().unwrap();
        self.heap.pop();
        self.heapify_down(0);
        Some(result)
    }

    fn is_empty(&self) -> bool {
        self.heap.is_empty()
    }

    fn heapify_up(&mut self, index: usize) {
        while index > 0 {
            let parent_index = (index - 1) / 2;
            if (self.comparator(&self.heap[index], &self.heap[parent_index])) >= Ordering::Equal {
                self.heap.swap(index, parent_index);
                index = parent_index;
            } else {
                break;
            }
        }
    }

    fn heapify_down(&mut self, index: usize) {
        let last_index = self.heap.len() - 1;
        while index < last_index {
            let left_index = 2 * index + 1;
            let right_index = 2 * index + 2;
            let mut smaller_index = index;

            if left_index <= last_index && (self.comparator(&self.heap[left_index], &self.heap[smaller_index])) < Ordering::Equal {
                smaller_index = left_index;
            }

            if right_index <= last_index && (self.comparator(&self.heap[right_index], &self.heap[smaller_index])) < Ordering::Equal {
                smaller_index = right_index;
            }

            if smaller_index != index {
                self.heap.swap(index, smaller_index);
                index = smaller_index;
            } else {
                break;
            }
        }
    }
}
