fn solve(grid: Vec<Vec<i64>>, k: i64) -> i64 {
    let m = grid.len();
    let n = grid[0].len();
    let mut dist = vec![vec![i64::MAX; n]; m];
    dist[0][0] = 0;

    let dirs = [[0, 1], [1, 0]]; // right, down

    let mut pq = PriorityQueue::new(|a, b| a.0.cmp(&b.0));
    pq.push((0, 0, 0, 0)); // (cost, row, col, usedTransports)

    while let Some((cost, row, col, used)) = pq.pop() {
        if row == m - 1 && col == n - 1 {
            return cost;
        }

        if used > k {
            continue;
        }

        // Regular moves
        for &[dr, dc] in &dirs {
            let new_row = row + dr;
            let new_col = col + dc;
            if new_row < m && new_col < n {
                let new_cost = cost + grid[new_row][new_col];
                if new_cost < dist[new_row][new_col] {
                    dist[new_row][new_col] = new_cost;
                    pq.push((new_cost, new_row, new_col, used));
                }
            }
        }

        // Teleportation
        for i in 0..m {
            for j in 0..n {
                if grid[i][j] <= grid[row][col] && (i != row || j != col) {
                    if cost < dist[i][j] {
                        dist[i][j] = cost;
                        pq.push((cost, i, j, used + 1));
                    }
                }
            }
        }
    }

    dist[m - 1][n - 1]
}

struct PriorityQueue<T> {
    heap: Vec<T>,
    comparator: Box<dyn Fn(&T, &T) -> Ordering>,
}

impl<T> PriorityQueue<T> {
    fn new(comparator: impl Fn(&T, &T) -> Ordering + 'static) -> Self {
        PriorityQueue {
            heap: Vec::new(),
            comparator: Box::new(comparator),
        }
    }

    fn push(&mut self, value: T) {
        self.heap.push(value);
        self.heapify_up(self.heap.len() - 1);
    }

    fn pop(&mut self) -> Option<T> {
        if self.heap.is_empty() {
            return None;
        }
        let result = self.heap[0];
        self.heap[0] = self.heap.last().unwrap().clone();
        self.heap.pop();
        self.heapify_down(0);
        Some(result)
    }

    fn heapify_up(&mut self, index: usize) {
        while index > 0 {
            let parent_index = (index - 1) / 2;
            if (self.comparator(&self.heap[index], &self.heap[parent_index])) >= Ordering::Equal {
                self.heap.swap(index, parent_index);
                index = parent_index;
            } else {
                break;
            }
        }
    }

    fn heapify_down(&mut self, index: usize) {
        let last_index = self.heap.len() - 1;
        while index < last_index {
            let left_index = 2 * index + 1;
            let right_index = 2 * index + 2;
            let mut smaller_index = index;

            if left_index <= last_index && (self.comparator(&self.heap[left_index], &self.heap[smaller_index])) < Ordering::Equal {
                smaller_index = left_index;
            }

            if right_index <= last_index && (self.comparator(&self.heap[right_index], &self.heap[smaller_index])) < Ordering::Equal {
                smaller_index = right_index;
            }

            if smaller_index != index {
                self.heap.swap(index, smaller_index);
                index = smaller_index;
            } else {
                break;
            }
        }
    }
