function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const dist = Array(m).fill().map(() => Array(n).fill(Infinity));
    dist[0][0] = 0;

    const dirs = [[0, 1], [1, 0]]; // right, down

    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0, 0, 0]); // [cost, row, col, usedTransports]

    while (!pq.isEmpty()) {
        const [cost, row, col, used] = pq.dequeue();

        if (row === m - 1 && col === n - 1) return cost;

        if (used > k) continue;

        // Regular moves
        for (const [dr, dc] of dirs) {
            const newRow = row + dr;
            const newCol = col + dc;
            if (newRow >= 0 && newRow < m && newCol >= 0 && newCol < n) {
                const newCost = cost + grid[newRow][newCol];
                if (newCost < dist[newRow][newCol]) {
                    dist[newRow][newCol] = newCost;
                    pq.enqueue([newCost, newRow, newCol, used]);
                }
            }
        }

        // Teleportation
        for (let i = 0; i < m; i++) {
            for (let j = 0; j < n; j++) {
                if (grid[i][j] <= grid[row][col] && i !== row || j !== col) {
                    if (cost < dist[i][j]) {
                        dist[i][j] = cost;
                        pq.enqueue([cost, i, j, used + 1]);
                    }
                }
            }
        }
    }

    return dist[m - 1][n - 1];
}

class PriorityQueue {
    constructor(comparator) {
        this.comparator = comparator;
        this.heap = [];
    }

    enqueue(value) {
        this.heap.push(value);
        this.heapifyUp(this.heap.length - 1);
    }

    dequeue() {
        if (this.heap.length === 0) return null;
        const result = this.heap[0];
        this.heap[0] = this.heap.pop();
        this.heapifyDown(0);
        return result;
    }

    isEmpty() {
        return this.heap.length === 0;
    }

    heapifyUp(index) {
        while (index > 0) {
            const parentIndex = Math.floor((index - 1) / 2);
            if (this.comparator(this.heap[index], this.heap[parentIndex]) >= 0) {
                [this.heap[index], this.heap[parentIndex]] = [this.heap[parentIndex], this.heap[index]];
                index = parentIndex;
            } else {
                break;
            }
        }
    }

    heapifyDown(index) {
        const lastIndex = this.heap.length - 1;
        while (index < lastIndex) {
            const leftIndex = 2 * index + 1;
            const rightIndex = 2 * index + 2;
            let smallerIndex = index;

            if (leftIndex <= lastIndex && this.comparator(this.heap[leftIndex], this.heap[smallerIndex]) < 0) {
                smallerIndex = leftIndex;
            }

            if (rightIndex <= lastIndex && this.comparator(this.heap[rightIndex], this.heap[smallerIndex]) < 0) {
                smallerIndex = rightIndex;
            }

            if (smallerIndex !== index) {
                [this.heap[index], this.heap[smallerIndex]] = [this.heap[smallerIndex], this.heap[index]];
                index = smallerIndex;
            } else {
                break;
            }
        }
    }
}

